# same function with modification fastai.vision.learner._test_cnn
def test_cnn_trnsfrmr(m):
    if not isinstance(m, nn.Sequential) or not len(m) == 2:
        return False
    if hasattr(m[1], "_transformer"):
        return True
    return isinstance(m[1][0], (AdaptiveConcatPool2d, nn.AdaptiveAvgPool2d))


def reshape_tensor(x):
    x = x.squeeze()
    if x.ndim > 2:
        return x
    # get feature size(height, width)
    feature_size = int(np.sqrt(x.shape[0]))
    # get number of tokens
    num_tokens = x.shape[0] - feature_size**2
    return x[num_tokens:, :].reshape(feature_size, feature_size, -1).permute(2, 0, 1)


def temporarily_enable_grad(model):
    """
    Returns requires_grad status for the parameters of the model before changing them to true.
    Args:
        model : Model for whose params requires_grad is to be set to True
    Returns:
        old_states :  dictionary with model's old requires_grad states

    """
    old_states = {}

    for name, p in model.named_parameters(remove_duplicate=False):
        old_states[name] = p.requires_grad
        p.requires_grad = True

    return old_states


def restore_grad(model, old_states):
    """
    Restore model's requires_grad state as given in old_states
    Args:
        model : Model for whose params requires_grad is to be set
        old_states : dictionary to be used to det model's requires_grad params


    """

    for name, p in model.named_parameters(remove_duplicate=False):
        p.requires_grad = old_states[name]


# same function with modification fastai.vision.learner._cl_int_gradcam
def gradcam_trnsfrmr(
    self,
    idx,
    ds_type=None,
    heatmap_thresh=16,
    image=True,
):
    if ds_type == None:
        ds_type = DatasetType.Valid
    m = self.learn.model.eval()

    # To enable triggering of backward hook
    m_requires_grad_states_ori = temporarily_enable_grad(m)

    im, cl = self.learn.data.dl(ds_type).dataset[idx]
    cl = int(cl)
    xb, _ = self.data.one_item(
        im, detach=False, denorm=False
    )  # put into a minibatch of batch size = 1
    with hook_output(m[0]) as hook_a:
        with hook_output(m[0], grad=True) as hook_g:
            preds = m(xb)

            preds[0, int(cl)].backward()
    acts = hook_a.stored[0].cpu()  # activation maps
    grad = hook_g.stored[0][0].cpu()
    if hasattr(m[1], "_transformer"):
        acts = reshape_tensor(acts)
        grad = reshape_tensor(grad)

    # Restore model weights requires_grad
    restore_grad(m, m_requires_grad_states_ori)

    if (acts.shape[-1] * acts.shape[-2]) >= heatmap_thresh:
        grad_chan = grad.mean(1).mean(1)
        mult = F.relu(((acts * grad_chan[..., None, None])).sum(0))
        if image:
            xb_im = Image(xb[0])
            _, ax = plt.subplots()
            sz = list(xb_im.shape[-2:])
            xb_im.show(
                ax,
                title=f"pred. class: {self.pred_class[idx]}, actual class: {self.learn.data.classes[cl]}",
            )
            ax.imshow(
                mult,
                alpha=0.4,
                extent=(0, *sz[::-1], 0),
                interpolation="bilinear",
                cmap="magma",
            )

        return mult


